// dropos-dashboard-pages.js — node dropos-dashboard-pages.js
const fs=require('fs'),path=require('path'),{execSync}=require('child_process');
const files={"frontend/src/app/dashboard/analytics/page.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { useQuery } from \"@tanstack/react-query\";\nimport { motion } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { api } from \"../../../lib/api\";\nimport {\n  AreaChart, Area, BarChart, Bar, LineChart, Line,\n  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell,\n} from \"recharts\";\nimport {\n  TrendingUp, ShoppingCart, Users, Activity,\n  ArrowUpRight, ArrowDownRight, Download, Zap,\n} from \"lucide-react\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\", cyan: \"#06B6D4\", fuchsia: \"#C026D3\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\", grid: \"rgba(255,255,255,0.04)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\", grid: \"rgba(15,5,32,0.06)\" },\n};\n\nconst PERIODS = [\"7 days\", \"30 days\", \"90 days\", \"1 year\"];\n\n// Demo data — replaced by real API data when backend is up\nfunction generateDemoData(days: number) {\n  const data = [];\n  const now = new Date();\n  for (let i = days - 1; i >= 0; i--) {\n    const d = new Date(now);\n    d.setDate(d.getDate() - i);\n    const label = days <= 7\n      ? d.toLocaleDateString(\"en\", { weekday: \"short\" })\n      : days <= 31\n        ? d.toLocaleDateString(\"en\", { month: \"short\", day: \"numeric\" })\n        : d.toLocaleDateString(\"en\", { month: \"short\" });\n    const base = 5000 + Math.random() * 25000;\n    const orders = Math.floor(1 + Math.random() * 12);\n    data.push({ label, revenue: Math.round(base), orders, visitors: Math.floor(orders * (4 + Math.random() * 6)) });\n  }\n  return data;\n}\n\nconst TOP_PRODUCTS = [\n  { name: \"Brazilian Hair Bundle\", sold: 0, revenue: 0, color: V.v400 },\n  { name: \"LED Face Mask\",         sold: 0, revenue: 0, color: V.cyan },\n  { name: \"Collagen Gummies\",      sold: 0, revenue: 0, color: V.fuchsia },\n  { name: \"Men's Perfume Set\",     sold: 0, revenue: 0, color: \"#10B981\" },\n];\n\nconst TRAFFIC_SOURCES = [\n  { name: \"Direct\",    value: 38, color: V.v400 },\n  { name: \"WhatsApp\",  value: 29, color: \"#25D366\" },\n  { name: \"Instagram\", value: 18, color: V.fuchsia },\n  { name: \"Twitter\",   value: 10, color: \"#1D9BF0\" },\n  { name: \"Other\",     value: 5,  color: \"#64748B\" },\n];\n\nfunction CustomTooltip({ active, payload, label, t, fmt }: any) {\n  if (!active || !payload?.length) return null;\n  return (\n    <div className=\"rounded-2xl px-4 py-3 shadow-2xl\" style={{ background: t.card, border: `1px solid ${t.border}` }}>\n      <p className=\"text-xs font-semibold mb-2\" style={{ color: t.muted }}>{label}</p>\n      {payload.map((p: any) => (\n        <div key={p.dataKey} className=\"flex items-center gap-2 text-sm font-bold\" style={{ color: p.color }}>\n          <div className=\"w-2 h-2 rounded-full\" style={{ background: p.color }} />\n          {p.dataKey === \"revenue\" ? fmt(p.value) : p.value}\n        </div>\n      ))}\n    </div>\n  );\n}\n\nexport default function AnalyticsPage() {\n  const { theme } = useTheme();\n  const t = theme === \"dark\" ? T.dark : T.light;\n  const isDark = theme === \"dark\";\n  const [period, setPeriod] = useState(\"7 days\");\n  const storeId = useAuthStore(s => s.user?.stores?.[0]?.id);\n\n  const days = period === \"7 days\" ? 7 : period === \"30 days\" ? 30 : period === \"90 days\" ? 90 : 365;\n\n  const { data: analyticsData } = useQuery({\n    queryKey: [\"analytics\", storeId, period],\n    queryFn: () => api.get(`/analytics/${storeId}?period=${period}`).then(r => r.data.data),\n    enabled: !!storeId,\n  });\n\n  // Use real data if available, demo data otherwise\n  const chartData = analyticsData?.daily || generateDemoData(days);\n  const isDemo = !analyticsData;\n\n  const totalRevenue  = chartData.reduce((a: number, d: any) => a + (d.revenue || 0), 0);\n  const totalOrders   = chartData.reduce((a: number, d: any) => a + (d.orders  || 0), 0);\n  const totalVisitors = chartData.reduce((a: number, d: any) => a + (d.visitors || 0), 0);\n  const conversion    = totalVisitors > 0 ? ((totalOrders / totalVisitors) * 100).toFixed(1) : \"0.0\";\n\n  const fmt = (n: number) => {\n    const currency = \"NGN\";\n    return new Intl.NumberFormat(\"en\", { style: \"currency\", currency, maximumFractionDigits: 0, notation: n >= 1000000 ? \"compact\" : \"standard\" }).format(n);\n  };\n\n  const stats = [\n    { label: \"Total Revenue\",  value: fmt(totalRevenue),  delta: 12,  color: V.v400,    icon: TrendingUp },\n    { label: \"Total Orders\",   value: totalOrders,        delta: 8,   color: V.cyan,    icon: ShoppingCart },\n    { label: \"Visitors\",       value: totalVisitors,      delta: 24,  color: V.fuchsia, icon: Users },\n    { label: \"Conversion\",     value: `${conversion}%`,   delta: -2,  color: \"#10B981\", icon: Activity },\n  ];\n\n  return (\n    <div style={{ maxWidth: 1400, margin: \"0 auto\" }}>\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        className=\"flex items-start justify-between gap-4 mb-6\">\n        <div>\n          <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>Analytics</h1>\n          <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>\n            Track your store performance\n            {isDemo && <span style={{ color: V.v400 }}> · Demo data — connect backend to see real stats</span>}\n          </p>\n        </div>\n        <div className=\"flex items-center gap-2\">\n          {/* Period picker */}\n          <div className=\"flex rounded-xl overflow-hidden\" style={{ border: `1px solid ${t.border}` }}>\n            {PERIODS.map(p => (\n              <button key={p} onClick={() => setPeriod(p)}\n                className=\"px-3 py-2 text-xs font-semibold transition-all\"\n                style={{\n                  background: period === p ? V.v500 : t.card,\n                  color: period === p ? \"#fff\" : t.muted,\n                  borderRight: p !== \"1 year\" ? `1px solid ${t.border}` : \"none\",\n                }}>\n                {p}\n              </button>\n            ))}\n          </div>\n          <button className=\"flex items-center gap-2 px-3 py-2 rounded-xl text-xs font-semibold\"\n            style={{ border: `1px solid ${t.border}`, background: t.card, color: t.muted }}>\n            <Download size={12} /> Export\n          </button>\n        </div>\n      </motion.div>\n\n      {/* Stat cards */}\n      <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-3 mb-6\">\n        {stats.map((s, i) => (\n          <motion.div key={s.label} initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.07 }}\n            className=\"rounded-2xl p-4 relative overflow-hidden\"\n            style={{ background: t.card, border: `1px solid ${t.border}` }}>\n            <div className=\"absolute top-0 left-0 right-0 h-0.5\" style={{ background: `linear-gradient(90deg, transparent, ${s.color}60, transparent)` }} />\n            <div className=\"flex items-start justify-between mb-3\">\n              <div className=\"w-8 h-8 rounded-xl flex items-center justify-center\" style={{ background: `${s.color}18` }}>\n                <s.icon size={15} style={{ color: s.color }} />\n              </div>\n              <div className=\"flex items-center gap-1 text-xs font-semibold\"\n                style={{ color: s.delta >= 0 ? \"#10B981\" : \"#EF4444\" }}>\n                {s.delta >= 0 ? <ArrowUpRight size={12} /> : <ArrowDownRight size={12} />}\n                {Math.abs(s.delta)}%\n              </div>\n            </div>\n            <p className=\"text-xl font-black mb-0.5\" style={{ color: t.text }}>{s.value}</p>\n            <p className=\"text-xs\" style={{ color: t.muted }}>{s.label}</p>\n          </motion.div>\n        ))}\n      </div>\n\n      {/* Revenue chart */}\n      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}\n        className=\"rounded-2xl p-5 mb-4\"\n        style={{ background: t.card, border: `1px solid ${t.border}` }}>\n        <div className=\"flex items-center justify-between mb-5\">\n          <div>\n            <h2 className=\"font-bold text-sm\" style={{ color: t.text }}>Revenue</h2>\n            <p className=\"text-xs mt-0.5\" style={{ color: t.muted }}>{period}</p>\n          </div>\n          <div className=\"flex items-center gap-3 text-xs\" style={{ color: t.muted }}>\n            <div className=\"flex items-center gap-1.5\"><div className=\"w-2.5 h-2.5 rounded-full\" style={{ background: V.v400 }} />Revenue</div>\n          </div>\n        </div>\n        <ResponsiveContainer width=\"100%\" height={220}>\n          <AreaChart data={chartData} margin={{ top: 4, right: 0, left: -20, bottom: 0 }}>\n            <defs>\n              <linearGradient id=\"revGrad\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0%\" stopColor={V.v400} stopOpacity={0.25} />\n                <stop offset=\"100%\" stopColor={V.v400} stopOpacity={0} />\n              </linearGradient>\n            </defs>\n            <CartesianGrid strokeDasharray=\"3 3\" stroke={t.grid} vertical={false} />\n            <XAxis dataKey=\"label\" tick={{ fontSize: 10, fill: t.muted }} axisLine={false} tickLine={false} />\n            <YAxis tick={{ fontSize: 10, fill: t.muted }} axisLine={false} tickLine={false}\n              tickFormatter={v => v >= 1000 ? `${(v/1000).toFixed(0)}k` : v} />\n            <Tooltip content={<CustomTooltip t={t} fmt={fmt} />} />\n            <Area type=\"monotone\" dataKey=\"revenue\" stroke={V.v400} strokeWidth={2} fill=\"url(#revGrad)\" dot={false} />\n          </AreaChart>\n        </ResponsiveContainer>\n      </motion.div>\n\n      {/* Orders + Traffic row */}\n      <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-4 mb-4\">\n        {/* Orders bar chart */}\n        <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}\n          className=\"lg:col-span-2 rounded-2xl p-5\"\n          style={{ background: t.card, border: `1px solid ${t.border}` }}>\n          <div className=\"flex items-center justify-between mb-5\">\n            <h2 className=\"font-bold text-sm\" style={{ color: t.text }}>Orders</h2>\n            <div className=\"text-xs\" style={{ color: t.muted }}>{period}</div>\n          </div>\n          <ResponsiveContainer width=\"100%\" height={180}>\n            <BarChart data={chartData} margin={{ top: 4, right: 0, left: -20, bottom: 0 }}>\n              <CartesianGrid strokeDasharray=\"3 3\" stroke={t.grid} vertical={false} />\n              <XAxis dataKey=\"label\" tick={{ fontSize: 10, fill: t.muted }} axisLine={false} tickLine={false} />\n              <YAxis tick={{ fontSize: 10, fill: t.muted }} axisLine={false} tickLine={false} />\n              <Tooltip content={<CustomTooltip t={t} fmt={fmt} />} />\n              <Bar dataKey=\"orders\" fill={V.cyan} radius={[4, 4, 0, 0]} maxBarSize={32} />\n            </BarChart>\n          </ResponsiveContainer>\n        </motion.div>\n\n        {/* Traffic sources */}\n        <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.35 }}\n          className=\"rounded-2xl p-5\"\n          style={{ background: t.card, border: `1px solid ${t.border}` }}>\n          <h2 className=\"font-bold text-sm mb-5\" style={{ color: t.text }}>Traffic Sources</h2>\n          <div className=\"flex justify-center mb-4\">\n            <PieChart width={140} height={140}>\n              <Pie data={TRAFFIC_SOURCES} cx={70} cy={70} innerRadius={45} outerRadius={65} dataKey=\"value\" strokeWidth={0}>\n                {TRAFFIC_SOURCES.map((entry, i) => <Cell key={i} fill={entry.color} />)}\n              </Pie>\n            </PieChart>\n          </div>\n          <div className=\"space-y-2\">\n            {TRAFFIC_SOURCES.map(s => (\n              <div key={s.name} className=\"flex items-center justify-between\">\n                <div className=\"flex items-center gap-2\">\n                  <div className=\"w-2 h-2 rounded-full\" style={{ background: s.color }} />\n                  <span className=\"text-xs\" style={{ color: t.muted }}>{s.name}</span>\n                </div>\n                <span className=\"text-xs font-bold\" style={{ color: t.text }}>{s.value}%</span>\n              </div>\n            ))}\n          </div>\n        </motion.div>\n      </div>\n\n      {/* Top products */}\n      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}\n        className=\"rounded-2xl p-5\"\n        style={{ background: t.card, border: `1px solid ${t.border}` }}>\n        <div className=\"flex items-center justify-between mb-4\">\n          <h2 className=\"font-bold text-sm\" style={{ color: t.text }}>Top Products</h2>\n          <div className=\"flex items-center gap-2 text-xs font-semibold px-3 py-1.5 rounded-lg\"\n            style={{ background: \"rgba(107,53,232,0.1)\", color: V.v400, border: \"1px solid rgba(107,53,232,0.2)\" }}>\n            <Zap size={11} /> KIRO picks winners daily\n          </div>\n        </div>\n        <div className=\"space-y-3\">\n          {TOP_PRODUCTS.map((p, i) => (\n            <div key={p.name} className=\"flex items-center gap-3\">\n              <span className=\"text-xs font-black w-4\" style={{ color: t.muted }}>#{i + 1}</span>\n              <div className=\"flex-1\">\n                <div className=\"flex items-center justify-between mb-1\">\n                  <span className=\"text-sm font-semibold\" style={{ color: t.text }}>{p.name}</span>\n                  <span className=\"text-xs\" style={{ color: t.muted }}>{p.sold} sold</span>\n                </div>\n                <div className=\"h-1.5 rounded-full overflow-hidden\" style={{ background: isDark ? \"rgba(255,255,255,0.06)\" : \"#f1f5f9\" }}>\n                  <div className=\"h-full rounded-full\" style={{ width: `${20 + i * 15}%`, background: p.color }} />\n                </div>\n              </div>\n              <span className=\"text-xs font-bold w-16 text-right\" style={{ color: p.color }}>{fmt(p.revenue)}</span>\n            </div>\n          ))}\n        </div>\n        {isDemo && (\n          <p className=\"text-xs mt-4 text-center\" style={{ color: t.muted }}>\n            Connect your backend to see real product performance\n          </p>\n        )}\n      </motion.div>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/stores/page.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { useQuery, useMutation, useQueryClient } from \"@tanstack/react-query\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { api } from \"../../../lib/api\";\nimport { Store, Plus, ExternalLink, Edit2, Trash2, Globe, Zap, AlertCircle, Loader2, X, Check, Copy } from \"lucide-react\";\nimport toast from \"react-hot-toast\";\nimport Link from \"next/link\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\" };\n\nfunction StoreModal({ store, onClose, t, isDark, onSuccess }: any) {\n  const isEdit = !!store;\n  const [form, setForm] = useState({\n    name:        store?.name        || \"\",\n    description: store?.description || \"\",\n    slug:        store?.slug        || \"\",\n    currency:    store?.currency    || \"NGN\",\n    brandColor:  store?.brandColor  || \"#6B35E8\",\n    theme:       store?.theme       || \"classic\",\n  });\n\n  const inp = { padding: \"10px 14px\", borderRadius: 10, border: `1px solid ${t.border}`, background: isDark ? \"rgba(255,255,255,0.04)\" : \"#f9fafb\", color: t.text, fontSize: 13, outline: \"none\", width: \"100%\" } as any;\n\n  const mut = useMutation({\n    mutationFn: async () => {\n      if (isEdit) return api.put(`/stores/${store.id}`, form);\n      return api.post(\"/stores\", form);\n    },\n    onSuccess: () => { toast.success(isEdit ? \"Store updated\" : \"Store created!\"); onSuccess(); onClose(); },\n    onError: (e: any) => toast.error(e.response?.data?.message || \"Failed\"),\n  });\n\n  const THEMES = [\"classic\", \"dark-luxe\", \"boutique\", \"minimal-pro\", \"bold\", \"neon\"];\n\n  return (\n    <div className=\"fixed inset-0 z-50 flex items-center justify-center p-4\"\n      style={{ background: \"rgba(0,0,0,0.6)\", backdropFilter: \"blur(8px)\" }}\n      onClick={e => e.target === e.currentTarget && onClose()}>\n      <motion.div initial={{ opacity: 0, scale: 0.95, y: 16 }} animate={{ opacity: 1, scale: 1, y: 0 }}\n        className=\"w-full max-w-lg rounded-3xl overflow-hidden\"\n        style={{ background: isDark ? \"#181230\" : \"#fff\", border: `1px solid ${t.border}` }}>\n        <div className=\"flex items-center justify-between px-6 py-4\" style={{ borderBottom: `1px solid ${t.border}` }}>\n          <h2 style={{ fontSize: 16, fontWeight: 800, color: t.text }}>{isEdit ? \"Edit Store\" : \"Create Store\"}</h2>\n          <button onClick={onClose} style={{ color: t.muted }}><X size={18} /></button>\n        </div>\n        <div className=\"p-6 space-y-4 max-h-[70vh] overflow-y-auto\">\n          <div>\n            <label style={{ fontSize: 12, fontWeight: 600, color: t.muted, display: \"block\", marginBottom: 6 }}>Store Name *</label>\n            <input style={inp} value={form.name} onChange={e => { setForm(f => ({ ...f, name: e.target.value, slug: !isEdit ? e.target.value.toLowerCase().replace(/[^a-z0-9]/g, \"-\").replace(/-+/g, \"-\") : f.slug })); }} placeholder=\"e.g. Amaka's Hair Store\" />\n          </div>\n          <div>\n            <label style={{ fontSize: 12, fontWeight: 600, color: t.muted, display: \"block\", marginBottom: 6 }}>Store URL Slug *</label>\n            <div style={{ display: \"flex\", alignItems: \"center\", gap: 0 }}>\n              <span style={{ padding: \"10px 12px\", borderRadius: \"10px 0 0 10px\", border: `1px solid ${t.border}`, borderRight: \"none\", background: isDark ? \"rgba(255,255,255,0.02)\" : \"#f1f5f9\", fontSize: 12, color: t.muted, whiteSpace: \"nowrap\" }}>droposhq.com/store/</span>\n              <input style={{ ...inp, borderRadius: \"0 10px 10px 0\", borderLeft: \"none\" } as any} value={form.slug} onChange={e => setForm(f => ({ ...f, slug: e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, \"\") }))} placeholder=\"my-store\" />\n            </div>\n          </div>\n          <div>\n            <label style={{ fontSize: 12, fontWeight: 600, color: t.muted, display: \"block\", marginBottom: 6 }}>Description</label>\n            <textarea style={{ ...inp, resize: \"none\" } as any} rows={2} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} placeholder=\"What do you sell?\" />\n          </div>\n          <div className=\"grid grid-cols-2 gap-3\">\n            <div>\n              <label style={{ fontSize: 12, fontWeight: 600, color: t.muted, display: \"block\", marginBottom: 6 }}>Currency</label>\n              <select style={{ ...inp, cursor: \"pointer\" } as any} value={form.currency} onChange={e => setForm(f => ({ ...f, currency: e.target.value }))}>\n                <option value=\"NGN\">NGN (₦)</option>\n                <option value=\"USD\">USD ($)</option>\n                <option value=\"GBP\">GBP (£)</option>\n                <option value=\"GHS\">GHS (₵)</option>\n                <option value=\"KES\">KES (KSh)</option>\n              </select>\n            </div>\n            <div>\n              <label style={{ fontSize: 12, fontWeight: 600, color: t.muted, display: \"block\", marginBottom: 6 }}>Brand Color</label>\n              <div style={{ display: \"flex\", gap: 6, alignItems: \"center\" }}>\n                <input type=\"color\" value={form.brandColor} onChange={e => setForm(f => ({ ...f, brandColor: e.target.value }))}\n                  style={{ width: 40, height: 38, borderRadius: 8, border: `1px solid ${t.border}`, background: \"none\", cursor: \"pointer\", padding: 2 }} />\n                <input style={{ ...inp, flex: 1 } as any} value={form.brandColor} onChange={e => setForm(f => ({ ...f, brandColor: e.target.value }))} placeholder=\"#6B35E8\" />\n              </div>\n            </div>\n          </div>\n          <div>\n            <label style={{ fontSize: 12, fontWeight: 600, color: t.muted, display: \"block\", marginBottom: 8 }}>Theme</label>\n            <div className=\"grid grid-cols-3 gap-2\">\n              {THEMES.map(th => (\n                <button key={th} onClick={() => setForm(f => ({ ...f, theme: th }))} type=\"button\"\n                  style={{ padding: \"8px 10px\", borderRadius: 10, border: `1px solid ${form.theme === th ? V.v500 : t.border}`, background: form.theme === th ? `${V.v500}14` : \"transparent\", color: form.theme === th ? V.v400 : t.muted, fontSize: 11, fontWeight: 600, cursor: \"pointer\", textTransform: \"capitalize\" }}>\n                  {th.replace(\"-\", \" \")}\n                </button>\n              ))}\n            </div>\n          </div>\n        </div>\n        <div className=\"px-6 py-4 flex gap-3 justify-end\" style={{ borderTop: `1px solid ${t.border}` }}>\n          <button onClick={onClose} style={{ padding: \"10px 20px\", borderRadius: 10, border: `1px solid ${t.border}`, background: \"transparent\", color: t.muted, fontSize: 13, fontWeight: 600, cursor: \"pointer\" }}>Cancel</button>\n          <button onClick={() => mut.mutate()} disabled={mut.isPending || !form.name || !form.slug}\n            style={{ padding: \"10px 24px\", borderRadius: 10, border: \"none\", background: `linear-gradient(135deg,${V.v500},#3D1C8A)`, color: \"#fff\", fontSize: 13, fontWeight: 700, cursor: \"pointer\", display: \"flex\", alignItems: \"center\", gap: 6, opacity: (!form.name || !form.slug) ? 0.5 : 1 }}>\n            {mut.isPending ? <><Loader2 size={13} className=\"animate-spin\" /> Saving…</> : <><Check size={13} /> {isEdit ? \"Save\" : \"Create Store\"}</>}\n          </button>\n        </div>\n      </motion.div>\n    </div>\n  );\n}\n\nexport default function StoresPage() {\n  const { theme } = useTheme();\n  const isDark = theme === \"dark\";\n  const qc = useQueryClient();\n  const refreshUser = useAuthStore(s => s.refreshUser);\n\n  const t = {\n    card:   isDark ? \"#181230\"                : \"#fff\",\n    border: isDark ? \"rgba(255,255,255,0.06)\" : \"rgba(15,5,32,0.07)\",\n    text:   isDark ? \"#fff\"                   : \"#0D0918\",\n    muted:  isDark ? \"rgba(255,255,255,0.38)\" : \"rgba(13,9,24,0.45)\",\n  };\n\n  const [modal, setModal] = useState<null | \"create\" | any>(null);\n\n  const { data, isLoading, error, refetch } = useQuery({\n    queryKey: [\"my-stores\"],\n    queryFn: () => api.get(\"/stores\").then(r => r.data.data),\n  });\n\n  const deleteMut = useMutation({\n    mutationFn: (id: string) => api.delete(`/stores/${id}`),\n    onSuccess: () => { toast.success(\"Store deleted\"); refetch(); },\n    onError: () => toast.error(\"Failed to delete store\"),\n  });\n\n  const stores: any[] = Array.isArray(data) ? data : [];\n\n  const handleSuccess = () => { refetch(); refreshUser?.(); };\n\n  const copyLink = (slug: string) => {\n    navigator.clipboard.writeText(`https://droposhq.com/store/${slug}`);\n    toast.success(\"Link copied!\");\n  };\n\n  return (\n    <div style={{ maxWidth: 1400, margin: \"0 auto\" }}>\n      <div className=\"flex items-start justify-between mb-6\">\n        <div>\n          <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>My Stores</h1>\n          <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>{stores.length > 0 ? `${stores.length} store${stores.length !== 1 ? \"s\" : \"\"} active` : \"Create your first store to start selling\"}</p>\n        </div>\n        <button onClick={() => setModal(\"create\")}\n          style={{ display: \"flex\", alignItems: \"center\", gap: 7, padding: \"10px 18px\", borderRadius: 12, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg,${V.v500},#3D1C8A)`, color: \"#fff\", fontSize: 13, fontWeight: 700, boxShadow: \"0 4px 16px rgba(107,53,232,0.35)\" }}>\n          <Plus size={14} /> Create Store\n        </button>\n      </div>\n\n      {isLoading ? (\n        <div style={{ padding: 60, textAlign: \"center\" }}>\n          <Loader2 size={28} className=\"animate-spin\" style={{ margin: \"0 auto\", color: V.v400, display: \"block\" }} />\n          <p style={{ color: t.muted, fontSize: 13, marginTop: 12 }}>Loading stores…</p>\n        </div>\n      ) : error ? (\n        <div style={{ padding: 60, textAlign: \"center\", borderRadius: 16, background: t.card, border: `1px solid ${t.border}` }}>\n          <AlertCircle size={28} style={{ margin: \"0 auto 10px\", color: \"#EF4444\", display: \"block\" }} />\n          <p style={{ color: t.text, fontWeight: 700 }}>Could not load stores</p>\n          <p style={{ color: t.muted, fontSize: 13, marginTop: 4 }}>Check your connection and try again</p>\n        </div>\n      ) : stores.length === 0 ? (\n        <div style={{ padding: \"60px 24px\", textAlign: \"center\", borderRadius: 16, background: t.card, border: `1px solid ${t.border}` }}>\n          <div style={{ width: 72, height: 72, borderRadius: 22, background: \"rgba(6,182,212,0.1)\", border: \"1px solid rgba(6,182,212,0.2)\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", margin: \"0 auto 16px\" }}>\n            <Store size={32} color=\"#06B6D4\" />\n          </div>\n          <h3 style={{ fontSize: 17, fontWeight: 800, color: t.text, marginBottom: 8 }}>No stores yet</h3>\n          <p style={{ fontSize: 13, color: t.muted, marginBottom: 24, maxWidth: 360, margin: \"0 auto 24px\" }}>\n            Create your first store and you can start selling in under 60 seconds. KIRO will help you set it up.\n          </p>\n          <button onClick={() => setModal(\"create\")}\n            style={{ display: \"inline-flex\", alignItems: \"center\", gap: 7, padding: \"12px 24px\", borderRadius: 12, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg,${V.v500},#3D1C8A)`, color: \"#fff\", fontSize: 13, fontWeight: 700 }}>\n            <Plus size={14} /> Create your first store\n          </button>\n        </div>\n      ) : (\n        <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5\">\n          {stores.map((store: any, i: number) => (\n            <motion.div key={store.id} initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.08 }}\n              style={{ borderRadius: 18, background: t.card, border: `1px solid ${t.border}`, overflow: \"hidden\" }}>\n              {/* Header */}\n              <div style={{ padding: \"20px 20px 16px\", borderBottom: `1px solid ${t.border}` }}>\n                <div style={{ display: \"flex\", alignItems: \"flex-start\", justifyContent: \"space-between\", marginBottom: 12 }}>\n                  <div style={{ width: 44, height: 44, borderRadius: 13, background: `${store.brandColor || V.v500}18`, border: `1px solid ${store.brandColor || V.v500}25`, display: \"flex\", alignItems: \"center\", justifyContent: \"center\" }}>\n                    <Store size={20} style={{ color: store.brandColor || V.v400 }} />\n                  </div>\n                  <div style={{ display: \"flex\", gap: 4 }}>\n                    <button onClick={() => setModal(store)}\n                      style={{ padding: 7, borderRadius: 8, border: `1px solid ${t.border}`, background: \"transparent\", color: t.muted, cursor: \"pointer\", display: \"flex\" }}>\n                      <Edit2 size={13} />\n                    </button>\n                    <button onClick={() => { if (confirm(`Delete \"${store.name}\"? This cannot be undone.`)) deleteMut.mutate(store.id); }}\n                      style={{ padding: 7, borderRadius: 8, border: \"1px solid rgba(239,68,68,0.2)\", background: \"transparent\", color: \"#EF4444\", cursor: \"pointer\", display: \"flex\" }}>\n                      <Trash2 size={13} />\n                    </button>\n                  </div>\n                </div>\n                <h3 style={{ fontSize: 15, fontWeight: 800, color: t.text, marginBottom: 4 }}>{store.name}</h3>\n                {store.description && <p style={{ fontSize: 12, color: t.muted, lineHeight: 1.5 }}>{store.description}</p>}\n              </div>\n              {/* Stats */}\n              <div className=\"grid grid-cols-2\" style={{ padding: \"12px 20px\", gap: 12 }}>\n                {[\n                  { label: \"Products\", value: store._count?.products ?? store.productCount ?? \"—\" },\n                  { label: \"Orders\", value: store._count?.orders ?? store.orderCount ?? \"—\" },\n                ].map(s => (\n                  <div key={s.label}>\n                    <p style={{ fontSize: 11, color: t.muted }}>{s.label}</p>\n                    <p style={{ fontSize: 18, fontWeight: 900, color: t.text }}>{s.value}</p>\n                  </div>\n                ))}\n              </div>\n              {/* Actions */}\n              <div style={{ padding: \"0 16px 16px\", display: \"flex\", gap: 8 }}>\n                <Link href={`/store/${store.slug}`} target=\"_blank\"\n                  className=\"flex items-center gap-1.5 flex-1 justify-center py-2.5 rounded-xl text-xs font-bold transition-all hover:opacity-80\"\n                  style={{ border: `1px solid ${t.border}`, color: t.muted, background: \"transparent\" }}>\n                  <ExternalLink size={12} /> View Store\n                </Link>\n                <button onClick={() => copyLink(store.slug)}\n                  className=\"flex items-center gap-1.5 flex-1 justify-center py-2.5 rounded-xl text-xs font-bold transition-all hover:opacity-80\"\n                  style={{ border: `1px solid ${store.brandColor || V.v500}40`, color: store.brandColor || V.v400, background: `${store.brandColor || V.v500}08` }}>\n                  <Copy size={12} /> Copy Link\n                </button>\n              </div>\n            </motion.div>\n          ))}\n        </div>\n      )}\n\n      <AnimatePresence>\n        {modal && (\n          <StoreModal\n            store={modal === \"create\" ? null : modal}\n            onClose={() => setModal(null)}\n            t={t} isDark={isDark}\n            onSuccess={handleSuccess}\n          />\n        )}\n      </AnimatePresence>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/customers/page.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { useQuery } from \"@tanstack/react-query\";\nimport { motion } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { api } from \"../../../lib/api\";\nimport {\n  Users, Search, Download, Mail, Phone,\n  ShoppingBag, TrendingUp, Zap, ChevronRight,\n  ArrowUpRight, User,\n} from \"lucide-react\";\nimport Link from \"next/link\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\", cyan: \"#06B6D4\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\", row: \"rgba(255,255,255,0.02)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\", row: \"rgba(15,5,32,0.015)\" },\n};\n\nfunction fmt(n: number) {\n  return new Intl.NumberFormat(\"en\", { style: \"currency\", currency: \"NGN\", maximumFractionDigits: 0 }).format(n);\n}\n\nfunction CustomerRow({ customer, t, isDark, i }: any) {\n  const initials = customer.name?.split(\" \").map((w: string) => w[0]).slice(0, 2).join(\"\") || \"?\";\n  const colors   = [V.v400, V.cyan, \"#10B981\", \"#F59E0B\", \"#C026D3\", \"#06B6D4\"];\n  const color    = colors[i % colors.length];\n\n  return (\n    <motion.div initial={{ opacity: 0, x: -8 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: i * 0.04 }}\n      className=\"grid items-center gap-3 px-4 py-3 rounded-xl transition-all hover:opacity-80 cursor-pointer\"\n      style={{\n        gridTemplateColumns: \"36px 1fr 180px 100px 100px 80px\",\n        background: i % 2 === 0 ? t.row : \"transparent\",\n      }}>\n      {/* Avatar */}\n      <div className=\"w-9 h-9 rounded-xl flex items-center justify-center text-xs font-black text-white flex-shrink-0\"\n        style={{ background: `linear-gradient(135deg,${color},${color}99)` }}>\n        {initials}\n      </div>\n      {/* Name + email */}\n      <div className=\"min-w-0\">\n        <p className=\"text-sm font-semibold truncate\" style={{ color: t.text }}>{customer.name || \"Unknown\"}</p>\n        <p className=\"text-xs truncate\" style={{ color: t.muted }}>{customer.email}</p>\n      </div>\n      {/* Phone */}\n      <p className=\"text-xs truncate\" style={{ color: t.muted }}>{customer.phone || \"—\"}</p>\n      {/* Orders */}\n      <div className=\"flex items-center gap-1\">\n        <ShoppingBag size={11} style={{ color: V.cyan }} />\n        <span className=\"text-sm font-bold\" style={{ color: t.text }}>{customer._count?.orders || customer.totalOrders || 0}</span>\n      </div>\n      {/* Total spent */}\n      <p className=\"text-sm font-bold\" style={{ color: \"#10B981\" }}>{fmt(customer.totalSpent || 0)}</p>\n      {/* Actions */}\n      <div className=\"flex items-center gap-1.5\">\n        <a href={`mailto:${customer.email}`} className=\"w-7 h-7 rounded-lg flex items-center justify-center transition-all hover:opacity-70\"\n          style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n          <Mail size={11} style={{ color: t.muted }} />\n        </a>\n        <button className=\"w-7 h-7 rounded-lg flex items-center justify-center transition-all hover:opacity-70\"\n          style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n          <ChevronRight size={11} style={{ color: t.muted }} />\n        </button>\n      </div>\n    </motion.div>\n  );\n}\n\nexport default function CustomersPage() {\n  const { theme } = useTheme();\n  const isDark = theme === \"dark\";\n  const t = isDark ? T.dark : T.light;\n  const [search, setSearch] = useState(\"\");\n  const [sort, setSort] = useState(\"recent\");\n\n  const { data, isLoading } = useQuery({\n    queryKey: [\"customers\"],\n    queryFn: () => api.get(\"/customers\").then(r => r.data.data),\n  });\n\n  const customers: any[] = data || [];\n\n  const filtered = customers.filter(c =>\n    !search || c.name?.toLowerCase().includes(search.toLowerCase()) || c.email?.toLowerCase().includes(search.toLowerCase())\n  );\n\n  const stats = [\n    { label: \"Total Customers\",   value: customers.length,                                          color: V.v400,    icon: Users },\n    { label: \"New This Month\",    value: customers.filter((c: any) => {\n        const d = new Date(c.createdAt);\n        const now = new Date();\n        return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();\n      }).length,                                                                                       color: \"#10B981\", icon: ArrowUpRight },\n    { label: \"Total Revenue\",     value: fmt(customers.reduce((a: number, c: any) => a + (c.totalSpent || 0), 0)), color: V.cyan, icon: TrendingUp },\n    { label: \"Avg. Order Value\",  value: fmt(customers.length > 0\n        ? customers.reduce((a: number, c: any) => a + (c.totalSpent || 0), 0) / Math.max(customers.reduce((a: number, c: any) => a + (c.totalOrders || 0), 0), 1)\n        : 0),                                                                                         color: \"#F59E0B\", icon: ShoppingBag },\n  ];\n\n  return (\n    <div style={{ maxWidth: 1400, margin: \"0 auto\" }}>\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        className=\"flex items-start justify-between gap-4 mb-6\">\n        <div>\n          <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>Customers</h1>\n          <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>\n            {customers.length > 0 ? `${customers.length} customer${customers.length !== 1 ? \"s\" : \"\"}` : \"View and manage your customer base\"}\n          </p>\n        </div>\n        <div className=\"flex gap-2\">\n          <button className=\"flex items-center gap-2 px-3 py-2 rounded-xl text-xs font-semibold\"\n            style={{ border: `1px solid ${t.border}`, color: t.muted, background: t.card }}>\n            <Download size={12} /> Export\n          </button>\n          <Link href=\"/dashboard/kai\"\n            className=\"flex items-center gap-2 px-3 py-2 rounded-xl text-xs font-semibold\"\n            style={{ background: \"rgba(107,53,232,0.1)\", color: V.v300, border: \"1px solid rgba(107,53,232,0.2)\" }}>\n            <Zap size={12} /> KIRO Insights\n          </Link>\n        </div>\n      </motion.div>\n\n      {/* Stats */}\n      <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-3 mb-6\">\n        {stats.map((s, i) => (\n          <motion.div key={s.label} initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.07 }}\n            className=\"rounded-2xl p-4 relative overflow-hidden\"\n            style={{ background: t.card, border: `1px solid ${t.border}` }}>\n            <div className=\"absolute top-0 left-0 right-0 h-0.5\" style={{ background: `linear-gradient(90deg, transparent, ${s.color}60, transparent)` }} />\n            <div className=\"w-8 h-8 rounded-xl flex items-center justify-center mb-3\" style={{ background: `${s.color}18` }}>\n              <s.icon size={15} style={{ color: s.color }} />\n            </div>\n            <p className=\"text-xl font-black mb-0.5\" style={{ color: t.text }}>{s.value}</p>\n            <p className=\"text-xs\" style={{ color: t.muted }}>{s.label}</p>\n          </motion.div>\n        ))}\n      </div>\n\n      {/* Table */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}\n        className=\"rounded-2xl overflow-hidden\"\n        style={{ background: t.card, border: `1px solid ${t.border}` }}>\n\n        {/* Toolbar */}\n        <div className=\"flex items-center gap-3 px-4 py-3\" style={{ borderBottom: `1px solid ${t.border}` }}>\n          <div className=\"flex items-center gap-2 flex-1 px-3 py-2 rounded-xl\"\n            style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n            <Search size={12} style={{ color: t.muted }} />\n            <input value={search} onChange={e => setSearch(e.target.value)} placeholder=\"Search customers...\"\n              className=\"flex-1 bg-transparent border-none outline-none text-xs\"\n              style={{ color: t.text, fontFamily: \"'Plus Jakarta Sans', sans-serif\" }} />\n          </div>\n          <select value={sort} onChange={e => setSort(e.target.value)}\n            className=\"px-3 py-2 rounded-xl text-xs font-medium outline-none cursor-pointer\"\n            style={{ background: t.card, border: `1px solid ${t.border}`, color: t.muted }}>\n            <option value=\"recent\">Most Recent</option>\n            <option value=\"spent\">Highest Spend</option>\n            <option value=\"orders\">Most Orders</option>\n          </select>\n        </div>\n\n        {/* Column headers */}\n        <div className=\"grid px-4 py-2.5\" style={{ gridTemplateColumns: \"36px 1fr 180px 100px 100px 80px\", borderBottom: `1px solid ${t.border}` }}>\n          {[\"\", \"Customer\", \"Phone\", \"Orders\", \"Total Spent\", \"\"].map((h, i) => (\n            <div key={i} className=\"text-[10px] font-bold uppercase tracking-wider\" style={{ color: t.muted, fontFamily: \"'Syncopate', sans-serif\", paddingLeft: i === 0 ? 0 : 4 }}>{h}</div>\n          ))}\n        </div>\n\n        {/* Rows */}\n        <div className=\"p-2\">\n          {isLoading ? (\n            Array.from({ length: 5 }).map((_, i) => (\n              <div key={i} className=\"h-14 rounded-xl mb-1 animate-pulse\" style={{ background: t.faint }} />\n            ))\n          ) : filtered.length > 0 ? (\n            filtered.map((c, i) => <CustomerRow key={c.id} customer={c} t={t} isDark={isDark} i={i} />)\n          ) : (\n            <div className=\"flex flex-col items-center justify-center py-20 text-center\">\n              <div className=\"w-14 h-14 rounded-2xl flex items-center justify-center mb-4\"\n                style={{ background: \"rgba(16,185,129,0.1)\", border: \"1px solid rgba(16,185,129,0.2)\" }}>\n                <Users size={24} color=\"#10B981\" />\n              </div>\n              <h3 className=\"font-bold text-sm mb-2\" style={{ color: t.text }}>\n                {search ? \"No customers found\" : \"No customers yet\"}\n              </h3>\n              <p className=\"text-xs mb-5\" style={{ color: t.muted, maxWidth: 300, lineHeight: 1.6 }}>\n                {search\n                  ? \"Try a different search term\"\n                  : \"Customers appear here once they make a purchase through your store. KIRO can help you get your first customer.\"}\n              </p>\n              {!search && (\n                <Link href=\"/dashboard/kai\"\n                  className=\"flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold text-white\"\n                  style={{ background: `linear-gradient(135deg, ${V.v500}, #3D1C8A)` }}>\n                  <Zap size={12} /> Ask KIRO to get first customers\n                </Link>\n              )}\n            </div>\n          )}\n        </div>\n      </motion.div>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/orders/page.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { useQuery, useMutation, useQueryClient } from \"@tanstack/react-query\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { api } from \"../../../lib/api\";\nimport {\n  ShoppingCart, Search, Filter, Download, Zap,\n  Package, Truck, Check, X, Clock, RefreshCw,\n  ChevronDown, Eye, ArrowUpRight, MoreHorizontal,\n  User, MapPin, Phone, Mail, Calendar,\n} from \"lucide-react\";\nimport toast from \"react-hot-toast\";\n\nconst V = { v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\", cyan: \"#06B6D4\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\", row: \"rgba(255,255,255,0.02)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\", row: \"rgba(15,5,32,0.015)\" },\n};\n\nconst STATUS: Record<string, { label: string; color: string; bg: string; icon: any }> = {\n  PENDING:   { label: \"Pending\",   color: \"#F59E0B\", bg: \"rgba(245,158,11,0.12)\",  icon: Clock },\n  PAID:      { label: \"Paid\",      color: \"#10B981\", bg: \"rgba(16,185,129,0.12)\",  icon: Check },\n  SHIPPED:   { label: \"Shipped\",   color: \"#06B6D4\", bg: \"rgba(6,182,212,0.12)\",   icon: Truck },\n  DELIVERED: { label: \"Delivered\", color: V.v400,    bg: \"rgba(107,53,232,0.12)\",  icon: Package },\n  CANCELLED: { label: \"Cancelled\", color: \"#EF4444\", bg: \"rgba(239,68,68,0.12)\",   icon: X },\n  REFUNDED:  { label: \"Refunded\",  color: \"#8B5CF6\", bg: \"rgba(139,92,246,0.12)\",  icon: RefreshCw },\n};\n\nconst TABS = [\"All\", \"Pending\", \"Paid\", \"Shipped\", \"Delivered\", \"Cancelled\"];\n\nfunction fmt(n: number) {\n  return new Intl.NumberFormat(\"en\", { style: \"currency\", currency: \"NGN\", maximumFractionDigits: 0 }).format(n || 0);\n}\n\nfunction StatusBadge({ status }: { status: string }) {\n  const cfg = STATUS[status] || STATUS.PENDING;\n  const Icon = cfg.icon;\n  return (\n    <div className=\"inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold\"\n      style={{ background: cfg.bg, color: cfg.color }}>\n      <Icon size={10} />\n      {cfg.label}\n    </div>\n  );\n}\n\n// ── Order Detail Drawer ───────────────────────────────────────────────────────\nfunction OrderDrawer({ order, onClose, t, isDark }: { order: any; onClose: () => void; t: any; isDark: boolean }) {\n  const qc = useQueryClient();\n  const [newStatus, setNewStatus] = useState(order.status);\n  const [tracking, setTracking] = useState(order.trackingNumber || \"\");\n\n  const updateMut = useMutation({\n    mutationFn: () => api.put(`/orders/${order.storeId}/${order.id}`, { status: newStatus, trackingNumber: tracking }),\n    onSuccess: () => { toast.success(\"Order updated\"); qc.invalidateQueries({ queryKey: [\"orders\"] }); onClose(); },\n    onError: (e: any) => toast.error(e.response?.data?.message || \"Update failed\"),\n  });\n\n  return (\n    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}\n      className=\"fixed inset-0 z-50 flex items-center justify-end\"\n      style={{ background: \"rgba(0,0,0,0.6)\", backdropFilter: \"blur(8px)\" }}\n      onClick={e => e.target === e.currentTarget && onClose()}>\n      <motion.div initial={{ x: \"100%\" }} animate={{ x: 0 }} exit={{ x: \"100%\" }} transition={{ type: \"spring\", damping: 28 }}\n        className=\"h-full w-full max-w-md overflow-y-auto\"\n        style={{ background: isDark ? \"#181230\" : \"#fff\", borderLeft: `1px solid ${t.border}` }}>\n\n        {/* Header */}\n        <div className=\"flex items-center justify-between px-5 py-4\" style={{ borderBottom: `1px solid ${t.border}` }}>\n          <div>\n            <h2 className=\"font-bold text-sm\" style={{ color: t.text }}>Order #{order.id?.slice(-8)?.toUpperCase()}</h2>\n            <p className=\"text-xs mt-0.5\" style={{ color: t.muted }}>{new Date(order.createdAt).toLocaleDateString(\"en\", { day: \"numeric\", month: \"short\", year: \"numeric\" })}</p>\n          </div>\n          <button onClick={onClose} style={{ color: t.muted }}><X size={18} /></button>\n        </div>\n\n        <div className=\"p-5 space-y-5\">\n          {/* Status */}\n          <div className=\"rounded-2xl p-4\" style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n            <p className=\"text-xs font-semibold mb-3\" style={{ color: t.muted }}>Order Status</p>\n            <div className=\"grid grid-cols-3 gap-2\">\n              {Object.entries(STATUS).map(([key, cfg]) => {\n                const Icon = cfg.icon;\n                return (\n                  <button key={key} onClick={() => setNewStatus(key)}\n                    className=\"flex flex-col items-center gap-1 p-2 rounded-xl text-center transition-all\"\n                    style={{ background: newStatus === key ? cfg.bg : \"transparent\", border: `1px solid ${newStatus === key ? cfg.color : t.border}` }}>\n                    <Icon size={13} style={{ color: newStatus === key ? cfg.color : t.muted }} />\n                    <span className=\"text-[10px] font-semibold\" style={{ color: newStatus === key ? cfg.color : t.muted }}>{cfg.label}</span>\n                  </button>\n                );\n              })}\n            </div>\n          </div>\n\n          {/* Tracking */}\n          <div>\n            <label className=\"block text-xs font-semibold mb-2\" style={{ color: t.muted }}>Tracking Number</label>\n            <input value={tracking} onChange={e => setTracking(e.target.value)} placeholder=\"e.g. GIG-12345678\"\n              className=\"w-full px-3 py-2.5 rounded-xl text-sm outline-none\"\n              style={{ background: t.faint, border: `1px solid ${t.border}`, color: t.text, fontFamily: \"inherit\" }} />\n          </div>\n\n          {/* Customer */}\n          <div className=\"rounded-2xl p-4\" style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n            <p className=\"text-xs font-semibold mb-3\" style={{ color: t.muted }}>Customer</p>\n            <div className=\"space-y-2\">\n              {[\n                { icon: User,    val: order.customerName || order.customer?.name },\n                { icon: Mail,    val: order.customerEmail || order.customer?.email },\n                { icon: Phone,   val: order.customerPhone || order.customer?.phone },\n                { icon: MapPin,  val: order.shippingAddress?.address || order.deliveryAddress },\n              ].filter(i => i.val).map(({ icon: Icon, val }) => (\n                <div key={val} className=\"flex items-center gap-2\">\n                  <Icon size={12} style={{ color: t.muted, flexShrink: 0 }} />\n                  <span className=\"text-xs truncate\" style={{ color: t.text }}>{val}</span>\n                </div>\n              ))}\n            </div>\n          </div>\n\n          {/* Items */}\n          <div className=\"rounded-2xl p-4\" style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n            <p className=\"text-xs font-semibold mb-3\" style={{ color: t.muted }}>Items</p>\n            <div className=\"space-y-2\">\n              {(order.items || order.orderItems || []).map((item: any, i: number) => (\n                <div key={i} className=\"flex items-center gap-3\">\n                  <div className=\"w-8 h-8 rounded-lg overflow-hidden flex-shrink-0\"\n                    style={{ background: isDark ? \"rgba(255,255,255,0.06)\" : \"#f1f5f9\" }}>\n                    {item.product?.images?.[0]\n                      ? <img src={item.product.images[0]} alt=\"\" className=\"w-full h-full object-cover\" />\n                      : <Package size={12} style={{ color: t.muted, margin: \"auto\" }} />\n                    }\n                  </div>\n                  <div className=\"flex-1 min-w-0\">\n                    <p className=\"text-xs font-semibold truncate\" style={{ color: t.text }}>{item.product?.name || item.name || \"Product\"}</p>\n                    <p className=\"text-xs\" style={{ color: t.muted }}>Qty: {item.quantity} · {fmt(item.price)}</p>\n                  </div>\n                  <p className=\"text-xs font-bold\" style={{ color: t.text }}>{fmt((item.price || 0) * (item.quantity || 1))}</p>\n                </div>\n              ))}\n            </div>\n            <div className=\"flex justify-between mt-3 pt-3\" style={{ borderTop: `1px solid ${t.border}` }}>\n              <span className=\"text-xs font-semibold\" style={{ color: t.muted }}>Total</span>\n              <span className=\"text-sm font-black\" style={{ color: \"#10B981\" }}>{fmt(order.total || order.totalAmount)}</span>\n            </div>\n          </div>\n\n          {/* Save */}\n          <button onClick={() => updateMut.mutate()} disabled={updateMut.isPending}\n            className=\"w-full py-3 rounded-xl text-sm font-bold text-white flex items-center justify-center gap-2 transition-all hover:opacity-90 disabled:opacity-60\"\n            style={{ background: `linear-gradient(135deg, ${V.v500}, #3D1C8A)` }}>\n            {updateMut.isPending ? \"Saving...\" : \"Save Changes\"}\n          </button>\n        </div>\n      </motion.div>\n    </motion.div>\n  );\n}\n\n// ── Main Page ─────────────────────────────────────────────────────────────────\nexport default function OrdersPage() {\n  const { theme } = useTheme();\n  const isDark = theme === \"dark\";\n  const t = isDark ? T.dark : T.light;\n  const storeId = useAuthStore(s => s.user?.stores?.[0]?.id);\n  const [activeTab, setActiveTab] = useState(\"All\");\n  const [search, setSearch] = useState(\"\");\n  const [selectedOrder, setSelectedOrder] = useState<any>(null);\n\n  const { data, isLoading } = useQuery({\n    queryKey: [\"orders\", storeId, activeTab],\n    queryFn: () => api.get(`/orders/${storeId}${activeTab !== \"All\" ? `?status=${activeTab.toUpperCase()}` : \"\"}`).then(r => r.data.data),\n    enabled: !!storeId,\n  });\n\n  const orders: any[] = data?.orders || data || [];\n  const filtered = orders.filter(o =>\n    !search ||\n    o.id?.toLowerCase().includes(search.toLowerCase()) ||\n    (o.customerName || o.customer?.name || \"\").toLowerCase().includes(search.toLowerCase()) ||\n    (o.customerEmail || o.customer?.email || \"\").toLowerCase().includes(search.toLowerCase())\n  );\n\n  const stats = [\n    { label: \"Total Orders\",  value: orders.length,                                                    color: V.v400 },\n    { label: \"Pending\",       value: orders.filter((o: any) => o.status === \"PENDING\").length,          color: \"#F59E0B\" },\n    { label: \"Shipped\",       value: orders.filter((o: any) => o.status === \"SHIPPED\").length,          color: V.cyan },\n    { label: \"Revenue\",       value: fmt(orders.reduce((a: number, o: any) => a + (o.total || o.totalAmount || 0), 0)), color: \"#10B981\" },\n  ];\n\n  return (\n    <div style={{ maxWidth: 1400, margin: \"0 auto\" }}>\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        className=\"flex items-start justify-between gap-4 mb-6\">\n        <div>\n          <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>Orders</h1>\n          <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>Track and manage customer orders</p>\n        </div>\n        <div className=\"flex gap-2\">\n          <button className=\"flex items-center gap-2 px-3 py-2 rounded-xl text-xs font-semibold\"\n            style={{ border: `1px solid ${t.border}`, color: t.muted, background: t.card }}>\n            <Download size={12} /> Export\n          </button>\n          <button className=\"flex items-center gap-2 px-3 py-2 rounded-xl text-xs font-semibold\"\n            style={{ background: \"rgba(107,53,232,0.1)\", color: V.v300, border: \"1px solid rgba(107,53,232,0.2)\" }}>\n            <Zap size={12} /> KIRO Auto-fulfil\n          </button>\n        </div>\n      </motion.div>\n\n      {/* Stats */}\n      <div className=\"grid grid-cols-2 lg:grid-cols-4 gap-3 mb-5\">\n        {stats.map((s, i) => (\n          <motion.div key={s.label} initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.07 }}\n            className=\"rounded-2xl p-4 relative overflow-hidden\"\n            style={{ background: t.card, border: `1px solid ${t.border}` }}>\n            <div className=\"absolute top-0 left-0 right-0 h-0.5\" style={{ background: `linear-gradient(90deg, transparent, ${s.color}60, transparent)` }} />\n            <p className=\"text-2xl font-black mb-1\" style={{ color: s.color }}>{s.value}</p>\n            <p className=\"text-xs font-semibold\" style={{ color: t.text }}>{s.label}</p>\n          </motion.div>\n        ))}\n      </div>\n\n      {/* Table */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}\n        className=\"rounded-2xl overflow-hidden\"\n        style={{ background: t.card, border: `1px solid ${t.border}` }}>\n\n        {/* Tabs + toolbar */}\n        <div style={{ borderBottom: `1px solid ${t.border}` }}>\n          <div className=\"flex items-center px-4 gap-0 overflow-x-auto\" style={{ scrollbarWidth: \"none\" }}>\n            {TABS.map(tab => (\n              <button key={tab} onClick={() => setActiveTab(tab)}\n                className=\"py-3.5 px-3 text-xs font-semibold whitespace-nowrap transition-all flex-shrink-0\"\n                style={{ borderBottom: `2px solid ${activeTab === tab ? V.v500 : \"transparent\"}`, color: activeTab === tab ? t.text : t.muted }}>\n                {tab}\n              </button>\n            ))}\n            <div className=\"flex-1\" />\n            <div className=\"flex items-center gap-2 py-2\">\n              <div className=\"flex items-center gap-2 px-3 py-2 rounded-xl\"\n                style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n                <Search size={12} style={{ color: t.muted }} />\n                <input value={search} onChange={e => setSearch(e.target.value)} placeholder=\"Search orders...\"\n                  className=\"bg-transparent border-none outline-none text-xs w-36\"\n                  style={{ color: t.text, fontFamily: \"inherit\" }} />\n              </div>\n            </div>\n          </div>\n        </div>\n\n        {/* Column headers */}\n        <div className=\"hidden md:grid px-4 py-2.5\" style={{ gridTemplateColumns: \"1fr 160px 90px 110px 110px 60px\", borderBottom: `1px solid ${t.border}` }}>\n          {[\"Customer\", \"Date\", \"Items\", \"Status\", \"Total\", \"\"].map((h, i) => (\n            <div key={i} className=\"text-[10px] font-bold uppercase tracking-wider\" style={{ color: t.muted, fontFamily: \"'Syncopate', sans-serif\" }}>{h}</div>\n          ))}\n        </div>\n\n        {/* Rows */}\n        <div className=\"divide-y\" style={{ borderColor: t.border }}>\n          {isLoading ? (\n            Array.from({ length: 5 }).map((_, i) => (\n              <div key={i} className=\"h-16 px-4 flex items-center gap-3 animate-pulse\">\n                <div className=\"h-3 rounded-full w-1/4\" style={{ background: t.faint }} />\n                <div className=\"h-3 rounded-full w-1/6\" style={{ background: t.faint }} />\n              </div>\n            ))\n          ) : filtered.length > 0 ? (\n            filtered.map((order, i) => (\n              <motion.div key={order.id} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: i * 0.03 }}\n                className=\"hidden md:grid items-center px-4 py-3 cursor-pointer transition-all hover:opacity-80\"\n                style={{ gridTemplateColumns: \"1fr 160px 90px 110px 110px 60px\" }}\n                onClick={() => setSelectedOrder(order)}>\n                <div>\n                  <p className=\"text-sm font-semibold\" style={{ color: t.text }}>{order.customerName || order.customer?.name || \"Customer\"}</p>\n                  <p className=\"text-xs mt-0.5\" style={{ color: t.muted }}>#{order.id?.slice(-8)?.toUpperCase()}</p>\n                </div>\n                <p className=\"text-xs\" style={{ color: t.muted }}>\n                  {new Date(order.createdAt).toLocaleDateString(\"en\", { day: \"numeric\", month: \"short\" })}\n                </p>\n                <p className=\"text-xs font-semibold\" style={{ color: t.text }}>\n                  {(order.items || order.orderItems || []).length} item{(order.items || order.orderItems || []).length !== 1 ? \"s\" : \"\"}\n                </p>\n                <StatusBadge status={order.status} />\n                <p className=\"text-sm font-bold\" style={{ color: \"#10B981\" }}>{fmt(order.total || order.totalAmount)}</p>\n                <button className=\"flex items-center justify-center w-7 h-7 rounded-lg transition-all hover:opacity-70\"\n                  style={{ background: t.faint, border: `1px solid ${t.border}` }}>\n                  <Eye size={11} style={{ color: t.muted }} />\n                </button>\n              </motion.div>\n            ))\n          ) : (\n            <div className=\"flex flex-col items-center justify-center py-20 text-center\">\n              <div className=\"w-14 h-14 rounded-2xl flex items-center justify-center mb-4\"\n                style={{ background: \"rgba(6,182,212,0.1)\", border: \"1px solid rgba(6,182,212,0.2)\" }}>\n                <ShoppingCart size={24} color={V.cyan} />\n              </div>\n              <h3 className=\"font-bold text-sm mb-2\" style={{ color: t.text }}>\n                {search ? \"No orders found\" : \"No orders yet\"}\n              </h3>\n              <p className=\"text-xs mb-5\" style={{ color: t.muted, maxWidth: 300, lineHeight: 1.6 }}>\n                {search ? \"Try a different search\" : \"Once customers start buying, all orders appear here. KIRO can help you get your first sale.\"}\n              </p>\n              {!search && (\n                <button className=\"flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold text-white\"\n                  style={{ background: `linear-gradient(135deg, ${V.v500}, #3D1C8A)` }}>\n                  <Zap size={12} /> Ask KIRO to get first sales\n                </button>\n              )}\n            </div>\n          )}\n        </div>\n      </motion.div>\n\n      {/* Order detail drawer */}\n      <AnimatePresence>\n        {selectedOrder && <OrderDrawer order={selectedOrder} onClose={() => setSelectedOrder(null)} t={t} isDark={isDark} />}\n      </AnimatePresence>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/billing/page.tsx":"\"use client\";\n﻿\"use client\";\n// Path: frontend/src/app/dashboard/billing/page.tsx\n\nimport { useState } from \"react\";\nimport { motion } from \"framer-motion\";\nimport { useTheme } from \"../../../components/layout/DashboardLayout\";\nimport { Check, Zap, Crown, ArrowUpRight, CreditCard, Receipt, ChevronRight, Shield, Sparkles } from \"lucide-react\";\nimport { useAuthStore } from \"../../../store/auth.store\";\nimport { useMutation } from \"@tanstack/react-query\";\nimport { api } from \"../../../lib/api\";\nimport toast from \"react-hot-toast\";\n\nconst V = { v900: \"#1A0D3D\", v700: \"#3D1C8A\", v600: \"#5428C8\", v500: \"#6B35E8\", v400: \"#8B5CF6\", v300: \"#A78BFA\", v200: \"#C4B5FD\", fuchsia: \"#C026D3\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\" },\n};\n\nconst PLANS = [\n  {\n    id: \"FREE\", name: \"Free\", price: { ngn: 0, gbp: 0, usd: 0 },\n    icon: Sparkles, color: \"#6B7280\",\n    features: [\"1 store\", \"20 products\", \"KIRO 10 msgs/day\", \"Basic analytics\", \"2% transaction fee\", \"Community support\"],\n    limit: true,\n  },\n  {\n    id: \"GROWTH\", name: \"Growth\", price: { ngn: 9500, gbp: 12, usd: 15 },\n    icon: Zap, color: V.v400,\n    features: [\"1 store\", \"Unlimited products\", \"Full KIRO access\", \"Advanced analytics\", \"Custom domain\", \"1.5% transaction fee\", \"Email support 24hr\", \"Coupons & flash sales\", \"Abandoned cart recovery\"],\n    popular: true,\n  },\n  {\n    id: \"PRO\", name: \"Pro\", price: { ngn: 25000, gbp: 35, usd: 45 },\n    icon: Crown, color: \"#F59E0B\",\n    features: [\"Unlimited stores\", \"Everything in Growth\", \"KIRO Pro intelligence\", \"WhatsApp commerce bot\", \"1% transaction fee\", \"Email campaigns\", \"Loyalty programme\", \"3 staff accounts\", \"API access\", \"Priority support 2hr\"],\n  },\n];\n\nconst CURRENCY_LABELS: Record<string, string> = { ngn: \"₦\", gbp: \"£\", usd: \"$\" };\n\nexport default function BillingPage() {\n  const { theme } = useTheme();\n  const t = theme === \"dark\" ? T.dark : T.light;\n  const { user } = useAuthStore();\n  const [billing, setBilling] = useState<\"monthly\" | \"annual\">(\"monthly\");\n  const [currency, setCurrency] = useState<\"ngn\" | \"gbp\" | \"usd\">(\"ngn\");\n  const currentPlan = user?.subscription?.plan || \"FREE\";\n\n  const upgradeMut = useMutation({\n    mutationFn: (planId: string) => api.post(\"/billing/upgrade\", { plan: planId, currency, billing }),\n    onSuccess: (res) => {\n      const url = res.data?.data?.authorizationUrl || res.data?.data?.url;\n      if (url) { window.location.href = url; }\n      else { toast.success(\"Plan updated!\"); }\n    },\n    onError: (e: any) => toast.error(e.response?.data?.message || \"Upgrade failed — backend offline\"),\n  });\n\n  const handleUpgrade = (planId: string) => {\n    if (planId === \"FREE\") return; // downgrade handled separately\n    upgradeMut.mutate(planId);\n  };\n\n  return (\n    <div style={{ maxWidth: 1100, margin: \"0 auto\" }}>\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }}\n        style={{ display: \"flex\", alignItems: \"flex-start\", justifyContent: \"space-between\", gap: 16, marginBottom: 32 }}>\n        <div>\n          <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>Billing & Plans</h1>\n          <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>Manage your subscription and payment details</p>\n        </div>\n        <div style={{ display: \"flex\", gap: 8 }}>\n          <button style={{ display: \"flex\", alignItems: \"center\", gap: 6, padding: \"9px 14px\", borderRadius: 11, border: `1px solid ${t.border}`, background: \"transparent\", cursor: \"pointer\", fontSize: 13, color: t.muted }}>\n            <Receipt size={13} /> View Invoices\n          </button>\n        </div>\n      </motion.div>\n\n      {/* Current plan banner */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}\n        style={{ padding: \"18px 22px\", borderRadius: 16, marginBottom: 28, background: \"rgba(107,53,232,0.08)\", border: \"1px solid rgba(107,53,232,0.2)\", display: \"flex\", alignItems: \"center\", gap: 14 }}>\n        <div style={{ width: 40, height: 40, borderRadius: 12, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: `linear-gradient(145deg, ${V.v500}, ${V.v900})`, boxShadow: \"0 4px 14px rgba(107,53,232,0.3)\" }}>\n          <Zap size={18} color=\"white\" />\n        </div>\n        <div style={{ flex: 1 }}>\n          <div style={{ fontSize: 14, fontWeight: 700, color: t.text }}>You're on the <span style={{ color: V.v300 }}>{currentPlan}</span> plan</div>\n          <div style={{ fontSize: 12, color: t.muted, marginTop: 2 }}>Upgrade anytime. No contracts. Cancel anytime.</div>\n        </div>\n        <div style={{ display: \"flex\", alignItems: \"center\", gap: 8 }}>\n          <Shield size={13} color={V.v400} />\n          <span style={{ fontSize: 12, color: V.v400 }}>Secured by Paystack</span>\n        </div>\n      </motion.div>\n\n      {/* Billing toggle + currency */}\n      <div style={{ display: \"flex\", alignItems: \"center\", justifyContent: \"center\", gap: 16, marginBottom: 28 }}>\n        <div style={{ display: \"flex\", padding: 3, borderRadius: 12, background: t.card, border: `1px solid ${t.border}` }}>\n          {([\"monthly\", \"annual\"] as const).map(b => (\n            <button key={b} onClick={() => setBilling(b)}\n              style={{ padding: \"7px 20px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", fontSize: 13, fontWeight: billing === b ? 600 : 400, background: billing === b ? (theme === \"dark\" ? \"rgba(107,53,232,0.25)\" : \"rgba(107,53,232,0.12)\") : \"transparent\", color: billing === b ? (theme === \"dark\" ? V.v200 : V.v600) : t.muted, transition: \"all 0.15s\" }}>\n              {b === \"monthly\" ? \"Monthly\" : \"Annual\"}{b === \"annual\" && <span style={{ marginLeft: 6, fontSize: 10, fontWeight: 700, padding: \"1px 5px\", borderRadius: 4, background: \"rgba(16,185,129,0.2)\", color: \"#10B981\" }}>-17%</span>}\n            </button>\n          ))}\n        </div>\n        <div style={{ display: \"flex\", padding: 3, borderRadius: 12, background: t.card, border: `1px solid ${t.border}` }}>\n          {([\"ngn\", \"gbp\", \"usd\"] as const).map(c => (\n            <button key={c} onClick={() => setCurrency(c)}\n              style={{ padding: \"7px 14px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", fontSize: 13, fontWeight: currency === c ? 600 : 400, background: currency === c ? (theme === \"dark\" ? \"rgba(107,53,232,0.25)\" : \"rgba(107,53,232,0.12)\") : \"transparent\", color: currency === c ? (theme === \"dark\" ? V.v200 : V.v600) : t.muted, transition: \"all 0.15s\" }}>\n              {CURRENCY_LABELS[c]}{c.toUpperCase()}\n            </button>\n          ))}\n        </div>\n      </div>\n\n      {/* Plan cards */}\n      <div style={{ display: \"grid\", gridTemplateColumns: \"repeat(3, 1fr)\", gap: 16, marginBottom: 32 }}>\n        {PLANS.map((plan, i) => {\n          const Icon = plan.icon;\n          const isCurrent = currentPlan === plan.id;\n          const price = billing === \"annual\" ? Math.round(plan.price[currency] * 10) : plan.price[currency];\n          const isPopular = plan.popular;\n\n          return (\n            <motion.div key={plan.id} initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}\n              style={{ padding: 24, borderRadius: 20, position: \"relative\", overflow: \"hidden\", background: isPopular ? `linear-gradient(145deg, ${V.v900} 0%, #110D22 100%)` : t.card, border: `1px solid ${isPopular ? \"rgba(107,53,232,0.4)\" : isCurrent ? \"rgba(107,53,232,0.25)\" : t.border}`, boxShadow: isPopular ? \"0 8px 32px rgba(107,53,232,0.25)\" : theme === \"light\" ? \"0 1px 3px rgba(15,5,32,0.04), 0 4px 20px rgba(15,5,32,0.03)\" : \"none\" }}>\n\n              {/* Glow for popular */}\n              {isPopular && <div style={{ position: \"absolute\", top: -60, right: -60, width: 200, height: 200, borderRadius: \"50%\", background: \"radial-gradient(circle, rgba(107,53,232,0.2) 0%, transparent 70%)\", pointerEvents: \"none\" }} />}\n\n              {/* Popular badge */}\n              {isPopular && (\n                <div style={{ position: \"absolute\", top: 14, right: 14, fontFamily: \"'Syncopate', sans-serif\", fontSize: 7.5, fontWeight: 700, letterSpacing: \"0.1em\", padding: \"4px 8px\", borderRadius: 6, background: `linear-gradient(135deg, ${V.v500}, ${V.fuchsia})`, color: \"white\" }}>POPULAR</div>\n              )}\n\n              {/* Current badge */}\n              {isCurrent && !isPopular && (\n                <div style={{ position: \"absolute\", top: 14, right: 14, fontFamily: \"'Syncopate', sans-serif\", fontSize: 7.5, fontWeight: 700, letterSpacing: \"0.1em\", padding: \"4px 8px\", borderRadius: 6, background: \"rgba(16,185,129,0.15)\", color: \"#10B981\", border: \"1px solid rgba(16,185,129,0.25)\" }}>CURRENT</div>\n              )}\n\n              {/* Plan icon */}\n              <div style={{ width: 44, height: 44, borderRadius: 14, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", marginBottom: 16, background: `${plan.color}20`, border: `1px solid ${plan.color}30` }}>\n                <Icon size={20} color={plan.color} />\n              </div>\n\n              <div style={{ fontFamily: \"'Syncopate', sans-serif\", fontSize: 11, fontWeight: 700, letterSpacing: \"0.1em\", color: plan.color, marginBottom: 6 }}>{plan.name.toUpperCase()}</div>\n\n              <div style={{ marginBottom: 20 }}>\n                <span style={{ fontSize: 32, fontWeight: 800, letterSpacing: \"-0.04em\", color: isPopular ? \"#fff\" : t.text }}>\n                  {CURRENCY_LABELS[currency]}{price === 0 ? \"0\" : price.toLocaleString()}\n                </span>\n                {price > 0 && <span style={{ fontSize: 13, color: isPopular ? \"rgba(255,255,255,0.45)\" : t.muted }}>/mo</span>}\n                {price === 0 && <span style={{ fontSize: 13, color: isPopular ? \"rgba(255,255,255,0.45)\" : t.muted }}> forever</span>}\n                {billing === \"annual\" && price > 0 && <div style={{ fontSize: 11, color: \"#10B981\", marginTop: 3 }}>Billed annually · 2 months free</div>}\n              </div>\n\n              {/* CTA */}\n              <button\n                disabled={isCurrent || upgradeMut.isPending}\n                onClick={() => !isCurrent && handleUpgrade(plan.id)}\n                style={{ width: \"100%\", padding: \"11px\", borderRadius: 12, border: isCurrent ? `1px solid ${t.border}` : \"none\", cursor: isCurrent ? \"default\" : \"pointer\", fontSize: 13, fontWeight: 700, marginBottom: 20, background: isCurrent ? \"transparent\" : isPopular ? `linear-gradient(135deg, ${V.v500}, ${V.v700})` : `${plan.color}15`, color: isCurrent ? t.muted : isPopular ? \"white\" : plan.color, boxShadow: isPopular && !isCurrent ? \"0 4px 16px rgba(107,53,232,0.35)\" : \"none\", transition: \"all 0.15s\", opacity: upgradeMut.isPending ? 0.7 : 1 }}>\n                {upgradeMut.isPending && upgradeMut.variables === plan.id ? \"Opening Paystack...\" : isCurrent ? \"Current Plan\" : plan.id === \"FREE\" ? \"Downgrade\" : `Upgrade to ${plan.name}`}\n              </button>\n\n              {/* Features */}\n              <div style={{ display: \"flex\", flexDirection: \"column\", gap: 8 }}>\n                {plan.features.map(f => (\n                  <div key={f} style={{ display: \"flex\", alignItems: \"center\", gap: 8 }}>\n                    <div style={{ width: 16, height: 16, borderRadius: \"50%\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: `${plan.color}20`, flexShrink: 0 }}>\n                      <Check size={9} color={plan.color} />\n                    </div>\n                    <span style={{ fontSize: 12, color: isPopular ? \"rgba(255,255,255,0.7)\" : t.muted }}>{f}</span>\n                  </div>\n                ))}\n              </div>\n            </motion.div>\n          );\n        })}\n      </div>\n\n      {/* Payment method */}\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.4 }}\n        style={{ padding: 20, borderRadius: 16, background: t.card, border: `1px solid ${t.border}`, display: \"flex\", alignItems: \"center\", gap: 14 }}>\n        <div style={{ width: 40, height: 40, borderRadius: 12, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", background: t.faint, border: `1px solid ${t.border}` }}>\n          <CreditCard size={18} color={t.muted} />\n        </div>\n        <div style={{ flex: 1 }}>\n          <div style={{ fontSize: 13, fontWeight: 600, color: t.text }}>No payment method added</div>\n          <div style={{ fontSize: 12, color: t.muted, marginTop: 2 }}>Add a card or bank account to upgrade your plan</div>\n        </div>\n        <button style={{ display: \"flex\", alignItems: \"center\", gap: 6, padding: \"8px 16px\", borderRadius: 10, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg, ${V.v500}, ${V.v700})`, color: \"white\", fontSize: 13, fontWeight: 600, boxShadow: \"0 4px 12px rgba(107,53,232,0.3)\" }}>\n          Add Payment Method <ChevronRight size={13} />\n        </button>\n      </motion.div>\n    </div>\n  );\n}\n","frontend/src/app/dashboard/settings/page.tsx":"\"use client\";\n﻿\"use client\";\n// Path: frontend/src/app/dashboard/settings/page.tsx\n\nimport { useState } from \"react\";\nimport { motion } from \"framer-motion\";\nimport { useTheme, useToast, useConfirm } from \"../../../components/layout/DashboardLayout\";\nimport { Settings, User, Bell, Shield, Globe, Palette, Trash2, ChevronRight, Camera, Check, Eye, EyeOff } from \"lucide-react\";\nimport { api } from \"../../../lib/api\";\nimport { useAuthStore } from \"../../../store/auth.store\";\n\nconst V = { v500: \"#6B35E8\", v700: \"#3D1C8A\", v400: \"#8B5CF6\", v300: \"#A78BFA\" };\nconst T = {\n  dark:  { card: \"#181230\", border: \"rgba(255,255,255,0.06)\", text: \"#fff\", muted: \"rgba(255,255,255,0.38)\", faint: \"rgba(255,255,255,0.04)\", input: \"rgba(255,255,255,0.05)\" },\n  light: { card: \"#fff\",    border: \"rgba(15,5,32,0.07)\",    text: \"#0D0918\", muted: \"rgba(13,9,24,0.45)\", faint: \"rgba(15,5,32,0.03)\", input: \"rgba(15,5,32,0.04)\" },\n};\n\nconst SECTIONS = [\n  { id: \"profile\",       label: \"Profile\",         icon: User },\n  { id: \"notifications\", label: \"Notifications\",    icon: Bell },\n  { id: \"security\",      label: \"Security\",         icon: Shield },\n  { id: \"appearance\",    label: \"Appearance\",       icon: Palette },\n  { id: \"language\",      label: \"Language\",         icon: Globe },\n  { id: \"danger\",        label: \"Danger Zone\",      icon: Trash2 },\n];\n\nfunction Input({ label, value, onChange, type = \"text\", placeholder, t, disabled }: any) {\n  const [show, setShow] = useState(false);\n  return (\n    <div>\n      <div style={{ fontSize: 12, fontWeight: 600, color: t.muted, marginBottom: 6, letterSpacing: \"0.02em\" }}>{label}</div>\n      <div style={{ position: \"relative\" }}>\n        <input\n          type={type === \"password\" ? (show ? \"text\" : \"password\") : type}\n          value={value} onChange={e => onChange(e.target.value)}\n          placeholder={placeholder} disabled={disabled}\n          style={{ width: \"100%\", padding: \"10px 14px\", borderRadius: 11, border: `1px solid ${t.border}`, background: disabled ? t.faint : t.input, color: t.text, fontSize: 14, fontFamily: \"'Plus Jakarta Sans', sans-serif\", outline: \"none\", paddingRight: type === \"password\" ? 40 : 14, opacity: disabled ? 0.6 : 1 }}\n        />\n        {type === \"password\" && (\n          <button onClick={() => setShow(!show)} style={{ position: \"absolute\", right: 12, top: \"50%\", transform: \"translateY(-50%)\", background: \"none\", border: \"none\", cursor: \"pointer\", color: t.muted }}>\n            {show ? <EyeOff size={14} /> : <Eye size={14} />}\n          </button>\n        )}\n      </div>\n    </div>\n  );\n}\n\nfunction Toggle({ label, desc, value, onChange, t }: any) {\n  return (\n    <div style={{ display: \"flex\", alignItems: \"center\", justifyContent: \"space-between\", padding: \"14px 0\", borderBottom: `1px solid ${t.border}` }}>\n      <div>\n        <div style={{ fontSize: 13, fontWeight: 600, color: t.text }}>{label}</div>\n        {desc && <div style={{ fontSize: 12, color: t.muted, marginTop: 2 }}>{desc}</div>}\n      </div>\n      <button onClick={() => onChange(!value)}\n        style={{ width: 44, height: 24, borderRadius: 12, border: \"none\", cursor: \"pointer\", position: \"relative\", background: value ? V.v500 : (t.faint === \"rgba(255,255,255,0.04)\" ? \"rgba(255,255,255,0.1)\" : \"rgba(15,5,32,0.1)\"), transition: \"all 0.2s\", boxShadow: value ? \"0 2px 8px rgba(107,53,232,0.3)\" : \"none\" }}>\n        <div style={{ position: \"absolute\", top: 2, left: value ? 22 : 2, width: 20, height: 20, borderRadius: \"50%\", background: \"white\", transition: \"left 0.2s\", boxShadow: \"0 1px 4px rgba(0,0,0,0.2)\" }} />\n      </button>\n    </div>\n  );\n}\n\nexport default function SettingsPage() {\n  const { theme } = useTheme();\n  const { show } = useToast();\n  const { confirm } = useConfirm();\n  const { user } = useAuthStore();\n  const t = theme === \"dark\" ? T.dark : T.light;\n  const [activeSection, setActiveSection] = useState(\"profile\");\n  const [saving, setSaving] = useState(false);\n  const [name, setName] = useState(user?.name || \"\");\n  const [email, setEmail] = useState(user?.email || \"\");\n  const [notifs, setNotifs] = useState({ orders: true, marketing: false, security: true, updates: true });\n\n  const handleSave = async () => {\n    setSaving(true);\n    try {\n      await api.put(\"/auth/profile\", { name, email });\n      show(\"Settings saved successfully\", \"success\");\n    } catch (e: any) {\n      // Backend offline — save locally at least\n      show(\"Saved locally (backend offline)\", \"info\");\n    } finally {\n      setSaving(false);\n    }\n  };\n\n  const handleDeleteAccount = async () => {\n    const ok = await confirm({ title: \"Delete your account?\", message: \"This will permanently delete your account and all your store data. This cannot be undone.\", confirmText: \"Yes, delete everything\", cancelText: \"Keep my account\", variant: \"danger\" });\n    if (ok) show(\"Account deletion requested\", \"info\");\n  };\n\n  const activeLabel = SECTIONS.find(s => s.id === activeSection)?.label || \"Settings\";\n\n  return (\n    <div style={{ maxWidth: 1000, margin: \"0 auto\" }}>\n      {/* Header */}\n      <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }} style={{ marginBottom: 24 }}>\n        <h1 style={{ fontSize: 22, fontWeight: 800, letterSpacing: \"-0.03em\", color: t.text }}>Settings</h1>\n        <p style={{ fontSize: 13, color: t.muted, marginTop: 4 }}>Manage your account and preferences</p>\n      </motion.div>\n\n      <div style={{ display: \"grid\", gridTemplateColumns: \"220px 1fr\", gap: 16 }}>\n        {/* Nav */}\n        <motion.div initial={{ opacity: 0, x: -8 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.1 }}\n          style={{ padding: 8, borderRadius: 16, background: t.card, border: `1px solid ${t.border}`, height: \"fit-content\", boxShadow: theme === \"light\" ? \"0 1px 3px rgba(15,5,32,0.04)\" : \"none\" }}>\n          {SECTIONS.map(s => {\n            const Icon = s.icon;\n            const isActive = activeSection === s.id;\n            const isDanger = s.id === \"danger\";\n            return (\n              <button key={s.id} onClick={() => setActiveSection(s.id)}\n                style={{ width: \"100%\", display: \"flex\", alignItems: \"center\", gap: 9, padding: \"9px 11px\", borderRadius: 11, border: \"none\", cursor: \"pointer\", background: isActive ? (isDanger ? \"rgba(239,68,68,0.1)\" : \"rgba(107,53,232,0.1)\") : \"transparent\", color: isActive ? (isDanger ? \"#EF4444\" : V.v300) : isDanger ? \"#EF4444\" : t.muted, marginBottom: 1, transition: \"all 0.15s\", textAlign: \"left\" }}>\n                <Icon size={14} />\n                <span style={{ fontSize: 13, fontWeight: isActive ? 600 : 400, flex: 1 }}>{s.label}</span>\n                {isActive && <ChevronRight size={12} />}\n              </button>\n            );\n          })}\n        </motion.div>\n\n        {/* Content */}\n        <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.15 }}\n          style={{ padding: 24, borderRadius: 16, background: t.card, border: `1px solid ${t.border}`, boxShadow: theme === \"light\" ? \"0 1px 3px rgba(15,5,32,0.04), 0 4px 20px rgba(15,5,32,0.03)\" : \"none\" }}>\n\n          <div style={{ fontSize: 16, fontWeight: 700, color: t.text, letterSpacing: \"-0.02em\", marginBottom: 20, paddingBottom: 16, borderBottom: `1px solid ${t.border}` }}>\n            {activeLabel}\n          </div>\n\n          {activeSection === \"profile\" && (\n            <div style={{ display: \"flex\", flexDirection: \"column\", gap: 20 }}>\n              {/* Avatar */}\n              <div style={{ display: \"flex\", alignItems: \"center\", gap: 16 }}>\n                <div style={{ position: \"relative\" }}>\n                  <div style={{ width: 72, height: 72, borderRadius: 20, background: `linear-gradient(145deg, ${V.v500}, ${V.v700})`, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", fontSize: 24, fontWeight: 700, color: \"white\" }}>\n                    {user?.name?.charAt(0)?.toUpperCase() || \"U\"}\n                  </div>\n                  <button style={{ position: \"absolute\", bottom: -4, right: -4, width: 26, height: 26, borderRadius: \"50%\", background: V.v500, border: `2px solid ${t.card}`, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", cursor: \"pointer\" }}>\n                    <Camera size={11} color=\"white\" />\n                  </button>\n                </div>\n                <div>\n                  <div style={{ fontSize: 16, fontWeight: 700, color: t.text }}>{user?.name || \"User\"}</div>\n                  <div style={{ fontSize: 12, color: t.muted }}>{user?.email}</div>\n                  <button style={{ marginTop: 6, fontSize: 12, color: V.v400, background: \"none\", border: \"none\", cursor: \"pointer\", padding: 0 }}>Change photo</button>\n                </div>\n              </div>\n\n              <div style={{ display: \"grid\", gridTemplateColumns: \"1fr 1fr\", gap: 14 }}>\n                <Input label=\"Full Name\" value={name} onChange={setName} placeholder=\"Your full name\" t={t} />\n                <Input label=\"Email Address\" value={email} onChange={setEmail} placeholder=\"you@example.com\" t={t} />\n              </div>\n              <Input label=\"Store Name\" value=\"\" onChange={() => {}} placeholder=\"My Awesome Store\" t={t} />\n              <Input label=\"WhatsApp Number\" value=\"\" onChange={() => {}} placeholder=\"+234 800 000 0000\" t={t} />\n\n              <button onClick={handleSave} disabled={saving}\n                style={{ alignSelf: \"flex-start\", display: \"flex\", alignItems: \"center\", gap: 8, padding: \"10px 22px\", borderRadius: 11, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg, ${V.v500}, ${V.v700})`, color: \"white\", fontSize: 13, fontWeight: 700, boxShadow: \"0 4px 14px rgba(107,53,232,0.35)\", opacity: saving ? 0.7 : 1 }}>\n                {saving ? <><span style={{ width: 14, height: 14, borderRadius: \"50%\", border: \"2px solid rgba(255,255,255,0.3)\", borderTopColor: \"white\", animation: \"spin 0.8s linear infinite\", display: \"inline-block\" }} /> Saving...</> : <><Check size={14} /> Save Changes</>}\n              </button>\n            </div>\n          )}\n\n          {activeSection === \"notifications\" && (\n            <div>\n              <Toggle label=\"New orders\" desc=\"Get notified when you receive a new order\" value={notifs.orders} onChange={(v: boolean) => setNotifs(n => ({ ...n, orders: v }))} t={t} />\n              <Toggle label=\"Marketing emails\" desc=\"Receive tips and product updates from DropOS\" value={notifs.marketing} onChange={(v: boolean) => setNotifs(n => ({ ...n, marketing: v }))} t={t} />\n              <Toggle label=\"Security alerts\" desc=\"Be notified of unusual account activity\" value={notifs.security} onChange={(v: boolean) => setNotifs(n => ({ ...n, security: v }))} t={t} />\n              <Toggle label=\"Platform updates\" desc=\"Stay informed about new features and changes\" value={notifs.updates} onChange={(v: boolean) => setNotifs(n => ({ ...n, updates: v }))} t={t} />\n              <button onClick={handleSave} style={{ marginTop: 20, display: \"flex\", alignItems: \"center\", gap: 8, padding: \"10px 22px\", borderRadius: 11, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg, ${V.v500}, ${V.v700})`, color: \"white\", fontSize: 13, fontWeight: 700, boxShadow: \"0 4px 14px rgba(107,53,232,0.35)\" }}>\n                <Check size={14} /> Save Preferences\n              </button>\n            </div>\n          )}\n\n          {activeSection === \"security\" && (\n            <div style={{ display: \"flex\", flexDirection: \"column\", gap: 16 }}>\n              <Input label=\"Current Password\" value=\"\" onChange={() => {}} type=\"password\" placeholder=\"Enter current password\" t={t} />\n              <Input label=\"New Password\" value=\"\" onChange={() => {}} type=\"password\" placeholder=\"Enter new password\" t={t} />\n              <Input label=\"Confirm New Password\" value=\"\" onChange={() => {}} type=\"password\" placeholder=\"Confirm new password\" t={t} />\n              <button style={{ alignSelf: \"flex-start\", display: \"flex\", alignItems: \"center\", gap: 8, padding: \"10px 22px\", borderRadius: 11, border: \"none\", cursor: \"pointer\", background: `linear-gradient(135deg, ${V.v500}, ${V.v700})`, color: \"white\", fontSize: 13, fontWeight: 700, boxShadow: \"0 4px 14px rgba(107,53,232,0.35)\" }}>\n                <Shield size={14} /> Update Password\n              </button>\n            </div>\n          )}\n\n          {activeSection === \"danger\" && (\n            <div style={{ display: \"flex\", flexDirection: \"column\", gap: 16 }}>\n              <div style={{ padding: 16, borderRadius: 12, background: \"rgba(239,68,68,0.08)\", border: \"1px solid rgba(239,68,68,0.18)\" }}>\n                <div style={{ fontSize: 14, fontWeight: 700, color: \"#EF4444\", marginBottom: 6 }}>Delete Account</div>\n                <div style={{ fontSize: 13, color: t.muted, marginBottom: 14, lineHeight: 1.6 }}>Once you delete your account, all your stores, products, orders and data will be permanently removed. This action cannot be undone.</div>\n                <button onClick={handleDeleteAccount} style={{ display: \"flex\", alignItems: \"center\", gap: 7, padding: \"10px 18px\", borderRadius: 10, border: \"1px solid rgba(239,68,68,0.3)\", background: \"rgba(239,68,68,0.1)\", color: \"#EF4444\", fontSize: 13, fontWeight: 600, cursor: \"pointer\" }}>\n                  <Trash2 size={14} /> Delete My Account\n                </button>\n              </div>\n            </div>\n          )}\n\n          {![\"profile\", \"notifications\", \"security\", \"danger\"].includes(activeSection) && (\n            <div style={{ display: \"flex\", flexDirection: \"column\", alignItems: \"center\", justifyContent: \"center\", padding: \"40px 24px\", textAlign: \"center\" }}>\n              <div style={{ fontSize: 13, color: t.muted }}>This section is coming soon.</div>\n            </div>\n          )}\n        </motion.div>\n      </div>\n    </div>\n  );\n}\n"};
let n=0;
for(const [rel,content] of Object.entries(files)){
  const p=rel.replace(/\//g,path.sep);
  fs.mkdirSync(path.dirname(p),{recursive:true});
  fs.writeFileSync(p,content,'utf8');
  console.log('OK ',rel.split('/').slice(-2).join('/'));
  n++;
}
console.log('\nWritten:',n,'files');
try{
  execSync('git add .',{stdio:'inherit'});
  const st=execSync('git status --short',{encoding:'utf8'}).trim();
  if(st){
    execSync('git commit -m "feat: Orders (drawer+status), Billing (Paystack), Settings (real API), Analytics (Recharts), Stores (create flow), Customers (table)"',{stdio:'inherit'});
    execSync('git push origin main',{stdio:'inherit'});
    console.log('\nPushed. Vercel deploying.');
  } else { console.log('\nAlready up to date.'); }
}catch(e){console.log('Git:',e.message);}
